svg.script:
const friction = 1e-4;
const acceleration = 0.2;
const topSpeed = 1;

let angle = 0;
let speed = 0;

let lastFrameTime;
let elapsedTime;

const wheel = document.getElementById("wheel");
const pedal = document.getElementById("pedal");

const wheelInitialAngle = wheel.transform.baseVal.length > 0 ? wheel.transform.baseVal[0].angle : 0;
const pedalInitialAngle = pedal.transform.baseVal.length > 0 ? pedal.transform.baseVal[0].angle : 0;

function main(newFrameTime) {
    if (lastFrameTime === undefined) {
        lastFrameTime = newFrameTime;
    }

    else {
        elapsedTime = newFrameTime - lastFrameTime;
        lastFrameTime = newFrameTime;

        angle = (angle + speed * elapsedTime) % 360;
        speed = Math.max(speed - friction * elapsedTime, 0);

        wheel.setAttribute("transform", `rotate(${wheelInitialAngle + angle})`);
        pedal.setAttribute("transform", `rotate(${pedalInitialAngle - angle})`);
    }

    requestAnimationFrame(main);
}

function accelerate() {
    speed = Math.min(speed + acceleration, topSpeed);
}

addEventListener("pointerdown", accelerate);

requestAnimationFrame(main);
